<template>
    <div>
        <Timer v-if="questionIsMounted" v-bind:question="test" v-on:updated="timerUpdate()"/>
        <p class="text-center h1 transition" id="testTitle"> {{test.title}}</p>
        <div v-for="(question, index) of test.questions" :key="index">
            <div class="transition condensable" id="condensable">
                <p class="text-center h4"> {{question.question.prompt}}</p>
                <div v-html="question.question.content"></div>
                <component :is="question.type" v-bind:question="question.question" v-bind:disabled="disableQuestion" @hook:mounted="questionMounted()" v-on:submit="submit"/>

            </div>
        </div>

        <button v-if="!test.reply" class="btn btn-primary m-2" @click="submit()"> Submit </button>

        <div class="card p-3 m-1" v-if="messages.submittionReply">
            <p class="text-center h4"> {{messages.submittionReply}} </p>
            <!-- <div v-if="!question.reply.continue" class="m-auto">
                <div v-if="this.question.reply.correct">
                    <button class="btn btn-success" @click="loadNewQuestion()">Load new question</button>
                </div>
                <div class="m-auto p-2" v-if="!this.question.reply.correct && !displayCorrectAnswer || question.reply.mistakes && question.reply.mistakes && !displayCorrectAnswer> 0">
                    <button class="btn btn-warning m-2" @click="tryAgain()">Try again</button>
                    <button class="btn btn-success m-2" @click="seeCorrectAnswer()">See correct answer</button>
                </div>
                <div v-if="displayCorrectAnswer" class="m-3 m-auto">
                    <p class="h5">Correct answer: {{question.reply.correctAnswer}}</p>
                </div>
            </div> -->
        </div>

    </div>
</template>

<script>
import MultipleChoice from './questions/MultipleChoice.vue'
import Cryptography from './questions/Cryptography.vue'
import ServerTalker from '../ServerTalker'
import Timer from './Timer'
export default {
    props: {
        userID: String,
        prop: String,
    },
    components: {
        MultipleChoice,
        Cryptography,
        Timer
    },
    data() {
        return {
            questions: [],
            test: {},
            paused: false,
            questionIsMounted: false,
            messages: {
                submissionReply: ''
            }
        }
    },
    async mounted() {
        //get test
        const response = await ServerTalker.loadTest(this.prop, this.userID, await this.$auth.getTokenSilently())
        this.test = response.test
        this.test.solution.time = 0
    },
    methods: {
        async submit() {
            const reply = await ServerTalker.submitTest(this.test, this.userID, await this.$auth.getTokenSilently())
            this.messages.submissionReply = reply.message
        },
        timerUpdate() {
            this.paused = this.test.paused
            const condensable = document.getElementById('condensable')
            const testTitle = document.getElementById('testTitle')
            //make blur
            if (this.question.paused) {
                testTitle.classList.add('blur')
                condensable.classList.add('condensed')
                
            } else {
                testTitle.classList.remove('blur')
                condensable.classList.remove('condensed')
            }
        },
        questionMounted() {
            this.questionIsMounted = true
            const condensable = document.getElementById('condensable')
            condensable.style.setProperty('--question-height', (condensable.offsetHeight + 500) + 'px')
        },
    }
}
</script>

<style>
    .transition {
        transition: all 300ms ease-in-out;
    }
    .condensable {
        --question-height: fit-content;
        overflow: hidden;
        max-height: var(--question-height);
    }
    .condensable.condensed {
        max-height: 0;
    }

    .transition.blur {
        color: transparent;
        text-shadow: 0 0 16px #000;
        -webkit-touch-callout: none;
        -webkit-user-select: none;
        -khtml-user-select: none;
        -moz-user-select: none;
        -ms-user-select: none;
        user-select: none;
    }
</style>